import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
import hashlib
import sqlite3
from datetime import datetime
import cv2
from sklearn.model_selection import train_test_split
import uuid

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Database setup
def init_db():
    conn = sqlite3.connect('model_data.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS training_data
                 (id INTEGER PRIMARY KEY, filename TEXT, hash TEXT, 
                  timestamp TEXT, user_id TEXT, label TEXT, verified BOOLEAN DEFAULT 0)''')
    c.execute('''CREATE TABLE IF NOT EXISTS model_versions
                 (version TEXT PRIMARY KEY, accuracy REAL, timestamp TEXT)''')
    conn.commit()
    conn.close()

# Initialize database
init_db()

# Data validation and cleaning
def validate_and_clean_data(df, file_path):
    # Remove rows with missing values
    df = df.dropna()
    
    # Remove duplicates
    df = df.drop_duplicates()
    
    # Basic data quality checks
    if len(df) == 0:
        raise ValueError("No valid data found in uploaded file")
    
    # Hash the file for integrity checking
    with open(file_path, 'rb') as f:
        file_hash = hashlib.md5(f.read()).hexdigest()
    
    return df, file_hash

# Image preprocessing
def preprocess_image(image_path, target_size=(224, 224)):
    image = cv2.imread(image_path)
    image = cv2.resize(image, target_size)
    image = image.astype(np.float32) / 255.0
    return image

# Create and compile model
def create_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='categorical_crossentropy',
                  metrics=['accuracy'])
    return model

# Data poisoning detection
def detect_poisoning(data, threshold=0.1):
    # Simple statistical anomaly detection
    if len(data) < 10:
        return False
    
    # Check for extreme values in numerical columns
    numerical_cols = data.select_dtypes(include=[np.number]).columns
    if len(numerical_cols) > 0:
        for col in numerical_cols:
            Q1 = data[col].quantile(0.25)
            Q3 = data[col].quantile(0.75)
            IQR = Q3 - Q1
            lower_bound = Q1 - 1.5 * IQR
            upper_bound = Q3 + 1.5 * IQR
            outliers = data[(data[col] < lower_bound) | (data[col] > upper_bound)]
            if len(outliers) / len(data) > threshold:
                return True
    
    return False

# Load and process training data
def load_training_data(file_path, user_id):
    try:
        # Validate file type
        if not file_path.lower().endswith('.csv'):
            raise ValueError("Only CSV files are allowed")
        
        # Load CSV
        df = pd.read_csv(file_path)
        
        # Validate and clean data
        df, file_hash = validate_and_clean_data(df, file_path)
        
        # Check for data poisoning
        if detect_poisoning(df):
            raise ValueError("Potential data poisoning detected")
        
        # Store in database
        conn = sqlite3.connect('model_data.db')
        c = conn.cursor()
        for index, row in df.iterrows():
            c.execute("INSERT INTO training_data (filename, hash, timestamp, user_id, label) VALUES (?, ?, ?, ?, ?)",
                     (os.path.basename(file_path), file_hash, datetime.now().isoformat(), user_id, str(row.iloc[-1])))
        conn.commit()
        conn.close()
        
        return df
        
    except Exception as e:
        raise ValueError(f"Error processing data: {str(e)}")

# Train model
def train_model(df, model_path='model.h5'):
    # Assuming last column is the label
    X = df.iloc[:, :-1].values
    y = df.iloc[:, -1].values
    
    # Convert labels to categorical
    unique_labels = np.unique(y)
    label_map = {label: i for i, label in enumerate(unique_labels)}
    y_categorical = tf.keras.utils.to_categorical([label_map[label] for label in y], num_classes=len(unique_labels))
    
    # Split data
    X_train, X_test, y_train, y_test = train_test_split(X, y_categorical, test_size=0.2, random_state=42)
    
    # Create and train model
    model = create_model(len(unique_labels))
    
    # Train model
    history = model.fit(X_train, y_train, epochs=10, batch_size=32, validation_data=(X_test, y_test))
    
    # Save model
    model.save(model_path)
    
    # Store model version
    conn = sqlite3.connect('model_data.db')
    c = conn.cursor()
    c.execute("INSERT INTO model_versions (version, accuracy, timestamp) VALUES (?, ?, ?)",
             (str(uuid.uuid4()), history.history['accuracy'][-1], datetime.now().isoformat()))
    conn.commit()
    conn.close()
    
    return model, history

# API endpoints
@app.route('/upload', methods=['POST'])
def upload_file():
    try:
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400
        
        file = request.files['file']
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
        
        if file:
            filename = secure_filename(file.filename)
            file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            file.save(file_path)
            
            # Get user ID from request or generate one
            user_id = request.form.get('user_id', str(uuid.uuid4()))
            
            # Load and process data
            df = load_training_data(file_path, user_id)
            
            # Train model with new data
            model, history = train_model(df)
            
            return jsonify({
                'message': 'Data uploaded and model trained successfully',
                'accuracy': history.history['accuracy'][-1],
                'loss': history.history['loss'][-1]
            })
            
    except Exception as e:
        return jsonify({'error': str(e)}), 400

