@app.route('/model_info', methods=['GET'])
def get_model_info():
    try:
        conn = sqlite3.connect('model_data.db')
        c = conn.cursor()
        c.execute("SELECT * FROM model_versions ORDER BY timestamp DESC LIMIT 1")
        latest_model = c.fetchone()
        conn.close()
        
        if latest_model:
            return jsonify({
                'version': latest_model[0],
                'accuracy': latest_model[1],
                'timestamp': latest_model[2]
            })
        else:
            return jsonify({'message': 'No model available'})
            
    except Exception as e:
        return jsonify({'error': str(e)}), 400

